2	import { ref, watch, nextTick, onUnmounted } from "vue";
3	import { gsap } from "gsap";
4	import { storeToRefs } from "pinia";
5	import { useElementStore } from "@/stores/elementStore";
6	import PeriodicGrid from "@/components/PeriodicGrid.vue";
7	import FilterBar from "@/components/FilterBar.vue";
8	import ColorModeSelector from "@/components/table/ColorModeSelector.vue";
9	import ColorLegend from "@/components/table/ColorLegend.vue";
10	import DetailModal from "@/components/detail/DetailModal.vue";
11	import { useElementFilter } from "@/composables/useElementFilter"
12	import ElementHoverCard from "@/components/ElementHoverCard.vue";
13	
14	const rootEl = ref<HTMLElement | null>(null);
15	let ctx: gsap.Context;
16	let entranceRan = false;
17	
18	const elementStore = useElementStore();
19	const { elements } = storeToRefs(elementStore);
20	
21	// Wire the GSAP dim/highlight tween for filter interactions
22	useElementFilter();
23	
24	// Run entrance animation once, after elements are loaded into the DOM.
25	// onMounted fires before the async loadElements() resolves, so tiles don't
26	// exist yet — watching the elements array and waiting for the next tick is
27	// the reliable trigger point.
28	const stopWatch = watch(
29	  elements,
30	  async (els) => {
31	    if (entranceRan || els.length === 0) return;
32	    entranceRan = true;
33	    stopWatch();
34	    // Extra nextTick after flush:"post" ensures child component renders
35	    // (PeriodicGrid's computed tiles) are fully committed before GSAP queries.
36	    // clearProps:"opacity,y" lets CSS classes (.is-dimmed) take back control
37	    // after the animation — without it, inline opacity:1 blocks filter dimming.
38	    await nextTick();
39	    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
40	    if (prefersReducedMotion) return;
41	    // Sort by visual top→bottom, left→right so the stagger follows the eye's
42	    // natural reading path instead of DOM/atomic-number order. Without this,
43	    // f-block tiles (appended last in the DOM) don't animate until after ALL
44	    // main-table tiles finish, producing a visible lag before the bottom rows appear.
45	    const tiles = Array.from(
46	      rootEl.value!.querySelectorAll<HTMLElement>(".element-tile")
47	    ).sort((a, b) => {
48	      const ra = a.getBoundingClientRect();
49	      const rb = b.getBoundingClientRect();
50	      return ra.top !== rb.top ? ra.top - rb.top : ra.left - rb.left;
51	    });
52	    // gsap.set runs synchronously here — we're still in the microtask queue
53	    // after nextTick, so the browser hasn't painted yet. This hides all tiles
54	    // before the first paint, preventing the flash of visible content that
55	    // gsap.from() causes (it sets initial props one rAF too late).
56	    gsap.set(tiles, { opacity: 0, y: 10 });
57	    ctx = gsap.context(() => {
58	      gsap.to(tiles, {
59	        opacity: 1,
60	        y: 0,
61	        stagger: 0.006,
62	        duration: 0.45,
63	        ease: "power2.out",
64	        clearProps: "opacity,y",
65	      });
66	    }, rootEl.value!);
67	  },
68	  { flush: "post" },
69	);
70	
71	onUnmounted(() => {
72	  stopWatch();
73	  ctx?.revert();
74	});
75	</script>
